Care dintre urmatoarele afirmatii este corecta?
Code:
#include <stdio.h>
#include <malloc.h>
#include <string.h>
#include <stdlib.h>

struct Student {
    int id;
    char* nume;
    float medie;
};

struct Nod {
    struct Student st;
    struct Nod* next;
};

int calculPozitie(char* key, int size) {
    int temp = 0;
    for (unsigned int i = 0; i < strlen(key); i++)
        temp += key[i];
    return (temp % size);
}

struct Student cautaHTable(struct Nod** hTab, int size, char* nume_student) {
    int k = calculPozitie(nume_student, size);
    struct Student stud;
    stud.nume = NULL;
    struct Nod* tmp = hTab[k];
    while (tmp) {
        if (!strcmp(tmp->st.nume, nume_student))
            stud = tmp->st;
        tmp = tmp->next;
    }
    return stud;
}

